1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	export function quote(input: { customer: { yearsWithMHPCO: number; previousContract: boolean }; items: { type: string }[] }): number {
13	  if (input.items.length === 0) return PROCESSING_FEE;
14	  const allRunes = input.items.every((item) => item.type === "rune");
15	  const basePremium =
16	    allRunes && input.items.length === 3
17	      ? 60
18	      : input.items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
19	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
20	  return basePremium + firstInsurance + PROCESSING_FEE;
21	}
